const SEED_PUBLIC_KEY = process.env.SEED_PUBLIC_KEY || "pk_test_2a8a5f07d4b9fcf1cc77e024";
const SEED_SECRET_KEY = process.env.SEED_SECRET_KEY || "sk_test_influish_demo";
